import os
import joblib
from google.cloud import storage

# Get model path from environment variable
model_path = os.environ.get('MODEL_PATH')

# Create a Cloud Storage client object
client = storage.Client()

# Get the latest model version from Cloud Storage
bucket_name = 'your-bucket-name'
blob_name = f'{model_path}/latest.joblib'
blob = client.bucket(bucket_name).blob(blob_name)

# Download the latest model version to local storage
blob.download_to_filename('latest_model.joblib')

# Load the latest model version
model = joblib.load('latest_model.joblib')

# Print a message indicating that the model has been loaded
print('Model loaded successfully.')